{
  "discovery": {
    "options": [
      {
        "feedback": "Correct! In German, the verb must be the second piece of information. If a time word takes the first spot, the verb comes next, pushing the subject to the third spot.",
        "isCorrect": true,
        "text": "The action word (verb) comes before the subject when the sentence starts with a time word."
      },
      {
        "feedback": "Compare the German sentences with their English translations. In English we say 'Today I learn', but the German literal order is 'Today learn I'.",
        "isCorrect": false,
        "text": "The action word always comes after the subject, exactly like in English."
      },
      {
        "feedback": "Actually, 'ich' (I), 'sie' (she), and 'wir' (we) are the subjects. They are still there, but notice their position compared to the verb.",
        "isCorrect": false,
        "text": "The sentence drops the subject completely when a time word is used."
      },
      {
        "feedback": "Look at where the highlighted words are placed. They come immediately after the first word ('Heute', 'Morgen', 'Jetzt'), not at the very end.",
        "isCorrect": false,
        "text": "The highlighted words are always placed at the very end of the sentence."
      }
    ],
    "question": "What pattern do you notice about the word order in the highlighted phrases?"
  },
  "examples": [
    {
      "highlight": "lerne ich",
      "romanization": null,
      "sentence": "Heute lerne ich Deutsch.",
      "translation": "Today I am learning German."
    },
    {
      "highlight": "arbeitet sie",
      "romanization": null,
      "sentence": "Morgen arbeitet sie.",
      "translation": "Tomorrow she works."
    },
    {
      "highlight": "spielen wir",
      "romanization": null,
      "sentence": "Jetzt spielen wir Fußball.",
      "translation": "Now we are playing soccer."
    }
  ],
  "exercises": [
    {
      "answers": [
        "geht er"
      ],
      "distractors": [
        "er geht",
        "gehen er",
        "er gehen"
      ],
      "feedback": "Because the time word 'Morgen' (Tomorrow) is in the first position, the verb 'geht' must take the second position, pushing the subject 'er' to the third.",
      "template": "Morgen [BLANK] nach Hause."
    },
    {
      "answers": [
        "essen wir"
      ],
      "distractors": [
        "wir essen",
        "isst wir",
        "wir isst"
      ],
      "feedback": "The sentence starts with 'Manchmal' (Sometimes) in position 1. The verb 'essen' must be in position 2, followed by the subject 'wir' in position 3.",
      "template": "Manchmal [BLANK] Pizza."
    }
  ],
  "ruleName": "Verb Second (V2) Word Order",
  "ruleSummary": "In German main clauses, the conjugated verb is always the second element. If you start a sentence with a time or place word, the verb stays in the second position, and the subject moves to the third position right after it."
}

